using System;

class Program
{
    // Dogrusal arama
    static int LinearSearch(int[] arr, int target)
    {
        for (int i = 0; i < arr.Length; i++)
        {
            if (arr[i] == target)
            {
                return i;
            }
        }
        return -1;
    }

    // Binary arama (dizi sirali olmali)
    static int BinarySearch(int[] arr, int target)
    {
        int left = 0;
        int right = arr.Length - 1;

        while (left <= right)
        {
            int mid = (left + right) / 2;

            if (arr[mid] == target)
            {
                return mid;
            }
            else if (arr[mid] < target)
            {
                left = mid + 1;
            }
            else
            {
                right = mid - 1;
            }
        }
        return -1;
    }

    static void Main()
    {
        int[] numbers = { 4, 12, 7, 23, 9, 1, 18 };

        int target = 23;
        int linearResult = LinearSearch(numbers, target);
        Console.WriteLine("Dogrusal arama: " + target + " indeks " + linearResult + "'de bulundu");

        // Binary arama icin dizi siralanmali
        int[] sortedNumbers = { 1, 4, 7, 9, 12, 18, 23 };
        int binaryResult = BinarySearch(sortedNumbers, target);
        Console.WriteLine("Binary arama: " + target + " indeks " + binaryResult + "'de bulundu");

        int notFound = LinearSearch(numbers, 99);
        Console.WriteLine("\n99 araniyor (bulunamayacak): " + notFound);
    }
}
